mapper.insert:


    SELECT
    TO_CHAR(SYSDATE, 'YYYYMMDD')
    || '_OFFLINE_'
    || LPAD(SEQ_RENT_CTRT.NEXTVAL, 5, '0')
    FROM DUAL



INSERT INTO RENT_CTRT (

RENT_CTRT_NO
,RENT_LSTG_NO
,MVIN_DT
,MVOUT_DT
,REG_DT
,CTRT_STTS_CD
,CTRT_APRV_DT
,CTRT_AMT
,MID_PAY_AMT
,BAL_AMT
,DPST_AMT
,MTHLY_RENT_AMT
,RENTOR_NM
,RENTOR_TELNO
,AGNT_NM
,AGNT_TELNO
,SPCL_STPLTN_CN
,SBMSN_DOC_NO

) VALUES (
#{rentCtrtNo}
,#{rentLstgNo}
,TO_DATE(#{mvinDt}, 'YYYY-MM-DD')
,TO_DATE(#{mvoutDt}, 'YYYY-MM-DD')
,SYSDATE
,'APPROVED'
,SYSDATE
,#{ctrtAmt}
,#{midPayAmt}
,#{balAmt}
,#{dpstAmt}
,#{mthlyRentAmt}
,#{rentorNm}
,#{rentorTelno}
,#{agntNm}
,#{agntTelno}
,#{spclStpltnCn}
,#{sbmsnDocNo}
)

INSERT INTO CTRT_MGR (
    CTRT_MGR_NO
    , USER_NO
    , MGR_ASGN_DT
    , CHG_YN
    , RENT_CTRT_NO
)VALUES (
    SEQ_CTRT_MGR.nextval
    ,#{userNo}
    ,SYSDATE
    ,'N'
    , #{rentCtrtNo}
    )

mapper.update:
UPDATE RENT_LISTING
SET DEAL_STTS_CD = 'CMP'
WHERE RENT_LSTG_NO = #{rentLstgNo}

mapper.select:
SELECT RCD.SBMSN_DOC_TY_CD
FROM RENT_CTRT_DOC RCD
WHERE RCD.RENT_LSTG_NO = #{rentLstgNo}
